#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class FilterTest : public testing::Test {
public:
  FilterTest() {
    filter_config_ = std::make_shared<Config>();
    filter_ = std::make_unique<CustomHeaderInjectionFilter>(filter_config_);
  }

  ConfigSharedPtr filter_config_;
  std::unique_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

TEST_F(FilterTest, DecodeHeadersWithoutRules) {
  filter_->setDecoderFilterCallbacks(decoder_callbacks_);
  Http::TestRequestHeaderMapImpl headers{{":method", "GET"}, {":path", "/"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
}

TEST_F(FilterTest, EncodeHeadersWithoutRules) {
  filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  Http::TestResponseHeaderMapImpl headers{{":status", "200"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(headers, false));
}

TEST_F(FilterTest, OnDestroy) {
  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

